    constructor(private apiService: ApiService) {
    }

    getCredentialDetails(): void {
        const entry = "did:tdw:QmPEZPhDFR4nEYSFK5bMnvECqdpf1tPTPJuWs9QrMjCumw:identifier-reg.trust-infra.swiyu-int.admin.ch:api:v1:did:9a5559f0-b81c-4368-a170-e7b4ae424527";

        this.apiService.getRegistryEntry(entry)
            .pipe(
                switchMap((registryEntry) => {
                    if (!!registryEntry) {
                        console.log("registryEntry", registryEntry)
                        this.registryEntry.set(registryEntry);
                        return of(registryEntry);
                    } else {
                        // Condition not met, return an empty observable
                        return of(null);
                    }
                }),
                switchMap(async (registryEntry) => {
                    const token = this.encodedCredential.split('~');

                    console.log("registryEntry[3]?.value?.id", registryEntry[3]?.value?.id);
                    if (!!registryEntry) {
                        const kid = "did:tdw:QmPEZPhDFR4nEYSFK5bMnvECqdpf1tPTPJuWs9QrMjCumw:identifier-reg.trust-infra.swiyu-int.admin.ch:api:v1:did:9a5559f0-b81c-4368-a170-e7b4ae424527#assert-key-f4bc032f-bfe0-4bab-acb3-bc3ef7fb3400"
                        const verificationMethod = registryEntry[3]?.value?.verificationMethod.map(meth => meth.id === kid ? meth : null).filter(meth => meth != null)[0];
                        const jwk = verificationMethod?.publicKeyJwk;
                        const {payload, protectedHeader} = await jose.jwtVerify(token[0], jwk);
                        this.decodedHeader.set(protectedHeader);
                        this.decodedPayload.set(payload);

                        let disclosures: any[] = [];

                        for (let i = 1; i < token.length - 1; i++) {
                            disclosures.push(JSON.parse(this.base64UrlDecode(token[i])));
                        }

                        this.disclosures.set(disclosures);

                        console.log("disclosures", disclosures)

                        return {payload, protectedHeader}
                    } else {
                        // Condition not met, return an empty observableö
                        return of(null);
                    }
                }),
                switchMap((test) => {
                    return of(test)
                })
            )
            .subscribe(res => {
                console.log("res", res)
            });
    }

    public ngOnChanges(changes: SimpleChanges) {
        // changes.prop contains the old and the new value...
        console.log("Credential changed", changes, this.encodedCredential);
        this.getCredentialDetails();
    }

    public onResolve(input: string): void {
        console.log("Credential changed", input);
        this.encodedCredential = input;
    }

    public getDisclosureEntries(disclosure: string[]) {
        console.log(disclosure);
        console.log(disclosure[0]);
        console.log(disclosure[1]);
        console.log(disclosure[2]);
        return disclosure;
    }

    public mimi(test: string) {
        console.log("mmi", test);
    }

    private base64UrlDecode(input: string): string {
        // convert base64url to base64
        input = input.replace(/-/g, '+').replace(/_/g, '/');
        const pad = input.length % 4;
        if (pad) input += '='.repeat(4 - pad);

        // decode to bytes and decode UTF-8
        const bytes = Uint8Array.from(atob(input), c => c.charCodeAt(0));
        return new TextDecoder().decode(bytes);
    }
